27: func UIDToIDHandler(teamService Service) func(ctx context.Context, orgID int64, resourceID string) (string, error) {
28: 	return func(ctx context.Context, orgID int64, teamIDorUID string) (string, error) {
29: 		// if teamIDorUID is empty or is an integer, we assume it's a team ID, and we don't need to resolve it
30: 		_, err := strconv.ParseInt(teamIDorUID, 10, 64)
31: 		if teamIDorUID == "" || err == nil {
32: 			return teamIDorUID, nil
33: 		}
34: 		team, err := teamService.GetTeamByID(ctx, &GetTeamByIDQuery{UID: teamIDorUID, OrgID: orgID})
35: 		if err != nil {
36: 			return "", err
37: 		}
38: 
39: 		return strconv.FormatInt(team.ID, 10), err
40: 	}
41: }
