43: func MiddlewareTeamUIDResolver(teamService Service, paramName string) web.Handler {
44: 	handler := UIDToIDHandler(teamService)
45: 
46: 	return func(c *contextmodel.ReqContext) {
47: 		// Get team id from request, fetch team and replace team UID with team ID
48: 		teamIDorUID := web.Params(c.Req)[paramName]
49: 		id, err := handler(c.Req.Context(), c.OrgID, teamIDorUID)
50: 		if err == nil {
51: 			gotParams := web.Params(c.Req)
52: 			gotParams[paramName] = id
53: 			web.SetURLParams(c.Req, gotParams)
54: 		} else {
55: 			c.JsonApiErr(http.StatusNotFound, "Not found", nil)
56: 		}
57: 	}
58: }
